-- 1. CLEAR OLD TABLES IF THEY EXIST
DROP TABLE IF EXISTS medical_history CASCADE;
DROP TABLE IF EXISTS doctors CASCADE;
DROP TABLE IF EXISTS patients CASCADE;

-- 2. CREATE TABLES
CREATE TABLE patients (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name TEXT NOT NULL,
    aadhar_no TEXT UNIQUE NOT NULL,
    mobile_no TEXT NOT NULL,
    state TEXT,
    city TEXT,
    district TEXT,
    password TEXT NOT NULL,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW())
);

CREATE TABLE doctors (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    name TEXT NOT NULL,
    aadhar_no TEXT UNIQUE NOT NULL,
    mobile_no TEXT NOT NULL,
    state TEXT,
    city TEXT,
    district TEXT,
    password TEXT NOT NULL,
    hospital_name TEXT NOT NULL,
    specialization TEXT DEFAULT 'General Physician',
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW())
);

CREATE TABLE medical_history (
    id UUID PRIMARY KEY DEFAULT uuid_generate_v4(),
    patient_name TEXT NOT NULL,
    patient_aadhar_no TEXT REFERENCES patients(aadhar_no) ON DELETE CASCADE,
    doctor_aadhar_no TEXT REFERENCES doctors(aadhar_no) ON DELETE SET NULL,
    doctor_name TEXT NOT NULL,
    hospital_name TEXT NOT NULL,
    past_medical_record TEXT NOT NULL,
    prescription TEXT,
    created_at TIMESTAMP WITH TIME ZONE DEFAULT TIMEZONE('utc'::text, NOW())
);

